<?php require_once __DIR__.'/../config.php'; require_once __DIR__.'/../includes/Database.php'; require_once __DIR__.'/../includes/RedisClient.php'; require_once __DIR__.'/../includes/Monitor.php'; $db=Database::getInstance();$pe=$db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='public_page_enabled'")??'1';if($pe!=='1'){http_response_code(404);die('Public status page disabled.');} $sn=$db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='site_name'")??'Status Monitor';$sd=$db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='site_description'")??'';$sites=$db->fetchAll("SELECT * FROM `sites` WHERE is_active=1 ORDER BY display_order ASC, name ASC");$cs=Monitor::getCurrentStatus();$summary=Monitor::getSummary();$hd=(int)($db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='history_days'")??90);$ci=(int)($db->fetchColumn("SELECT `value` FROM `settings` WHERE `key`='check_interval'")??300);$dates=[];for($i=$hd-1;$i>=0;$i--)$dates[]=date('Y-m-d',strtotime("-$i days"));$tx=['ok'=>'هœ¨ç؛؟','error'=>'ç¦»ç؛؟','warning'=>'è­¦ه‘ٹ','timeout'=>'è¶…و—¶','unknown'=>'وœھçں¥'];?><!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><meta name="description" content="<?php echo e($sd);?>"><title><?php echo e($sn);?> - وœچهٹ،çٹ¶و€پç›‘وژ§</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"><link href="https://fonts.googleapis.com/icon?family=Material+Icons" rel="stylesheet"><link href="/assets/css/public.css" rel="stylesheet"><script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.0/dist/chart.umd.min.js"></script></head><body><div class="container"><header><div class="header-content"><div class="header-left"><h1><span class="status-dot active"></span><?php echo e($sn);?></h1><p class="header-desc"><?php echo e($sd);?></p></div><div class="header-right"><div class="last-updated"><span class="material-icons">schedule</span><span>وœ€هگژو›´و–°: <?php echo $summary['last_checked']?date('Y-m-d H:i:s',strtotime($summary['last_checked'])):'N/A';?></span></div><div class="system-status"><span class="status-indicator active"></span><span>ç³»ç»ںè؟گè،Œن¸­</span></div></div></div></header><div class="summary-stats"><div class="summary-card"><div class="card-icon"><span class="material-icons">dns</span></div><div class="card-content"><span class="summary-value"><?php echo $summary['total_sites'];?></span><span class="summary-label">ç›‘وژ§ç«™ç‚¹</span></div></div><div class="summary-card online"><div class="card-icon"><span class="material-icons">check_circle</span></div><div class="card-content"><span class="summary-value"><?php echo $summary['online_sites'];?></span><span class="summary-label">هœ¨ç؛؟</span></div></div><div class="summary-card offline"><div class="card-icon"><span class="material-icons">error</span></div><div class="card-content"><span class="summary-value"><?php echo $summary['offline_sites'];?></span><span class="summary-label">ç¦»ç؛؟</span></div></div><div class="summary-card"><div class="card-icon"><span class="material-icons">speed</span></div><div class="card-content"><span class="summary-value"><?php echo $summary['avg_response'];?> ms</span><span class="summary-label">ه¹³ه‌‡ه“چه؛”</span></div></div></div><div class="status-grid"><?php foreach($sites as $s):$st=$cs[$s['id']]??['status'=>'unknown','http_code'=>null,'response_time'=>0,'error_message'=>'No data','checked_at'=>null];$ut=Monitor::getUptimeStats($s['id']);$tr=Monitor::getResponseTrend($s['id'],$hd);$cid='c'.$s['id'];?><div class="status-card <?php echo e($st['status']??'unknown');?>"><div class="status-header"><div class="site-info"><h3><?php echo e($s['name']);?></h3><a href="<?php echo e($s['url']);?>" target="_blank" rel="noopener" class="site-url"><?php echo e(parse_url($s['url'],PHP_URL_HOST));?> <span class="material-icons">open_in_new</span></a></div><div class="status-badge <?php echo e($s