php echo $l;?></span><div class="stat-bar"><div class="stat-bar-fill" style="width:<?php echo $ut[$k];?>%"></div><span class="stat-value"><?php echo $ut[$k];?>%</span></div></div><?php endforeach;?></div><div class="history-graph"><h4><span class="material-icons">timeline</span> وœ€è؟‘<?php echo $hd;?>ه¤©çٹ¶و€پ</h4><div class="graph-bars"><?php $tm=[];foreach($tr as $t)$tm[$t['check_date']]=$t;foreach($dates as $d):$ds=$tm[$d]??null;$oc=$ds['ok_count']??0;$tc=$ds['total_count']??0;$rt=$tc>0?($oc/$tc):0;$cl=$rt>=1?'ok':($rt>0?'partial':'unknown');?><div class="graph-bar" title="<?php echo e($d.': '.round($rt*100).'%');?>"><div class="bar-fill <?php echo $cl;?>" style="height:<?php echo max(10,$rt*100);?>%"></div></div><?php endforeach;?></div></div><div class="response-time-chart"><canvas id="<?php echo $cid;?>"></canvas></div></div><?php endforeach;?></div><?php if(empty($sites)):?><div class="empty-state"><span class="material-icons">monitor_heart</span><h3>وڑ‚و— ç›‘وژ§ç«™ç‚¹</h3><p>ç®،çگ†ه‘که°ڑوœھو·»هٹ ن»»ن½•ç›‘وژ§ç«™ç‚¹م€‚</p></div><?php endif;?><footer><p><?php echo e($sn);?> &copy; <?php echo date('Y');?> | ç‰ˆوœ¬ <?php echo APP_VERSION;?></p><p class="footer-info">و£€وµ‹é—´éڑ”: <?php echo ceil($ci/60);?> هˆ†é’ں | و•°وچ®ن؟‌ç•™ <?php echo $hd;?> ه¤©</p></footer></div><script><?php foreach($sites as $s):$cid='c'.$s['id'];$tr=Monitor::getResponseTrend($s['id'],$hd);?>(function(){var c=document.getElementById('<?php echo $cid;?>');if(!c)return;var t=<?php echo json_encode($tr,JSON_UNESCAPED_UNICODE);?>;new Chart(c,{type:'line',data:{labels:t.map(function(d){return d.check_date;}),datasets:[{label:'ه“چه؛”و—¶é—´(ms)',data:t.map(function(d){return d.avg_time?parseFloat(d.avg_time):null;}),borderColor:'#4361ee',backgroundColor:'rgba(67,97,238,.1)',fill:true,tension:.3,pointRadius:2,borderWidth:2}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{x:{grid:{display:false},ticks:{maxTicksLimit:10}},y:{beginAtZero:true,title:{display:true,text:'ms'}}}}});})();<?php endforeach;?>setTimeout(function(){location.reload();},<?php echo $ci*1000;?>);</script></body></html>